import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.BQ1gajhD.js";const p=JSON.parse('{"title":"天坛","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/temple-of-heaven.md","filePath":"landmarks/temple-of-heaven.md","lastUpdated":null}'),l={name:"landmarks/temple-of-heaven.md"};function n(i,t,h,s,d,u){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="天坛" tabindex="-1">天坛 <a class="header-anchor" href="#天坛" aria-label="Permalink to &quot;天坛&quot;">​</a></h1><blockquote><p>&quot;圜丘坛上望苍穹，祈谷殿中祷丰年。&quot; —— 清代诗人</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>天坛是明清两代皇帝&quot;祭天&quot;&quot;祈谷&quot;的场所，位于北京市东城区永定门内大街东侧。天坛占地约273公顷，是中国现存最大的古代祭祀建筑群，也是世界上现存规模最大、最完美的古代祭天建筑群。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:30-22:00（公园），8:00-17:30（景点）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">门票10元，联票28元（含祈年殿、回音壁、圜丘）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，秋季最美</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁5号线天坛东门站</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>明永乐十八年（1420年），明成祖朱棣建成北京天地坛，用于合祀天地。嘉靖九年（1530年），明世宗朱厚熜实行天地分祀，在南郊另建圜丘坛，专祀天；在北郊建方泽坛，专祀地。天地坛改称天坛。</p><h3 id="改建" tabindex="-1">改建 <a class="header-anchor" href="#改建" aria-label="Permalink to &quot;改建&quot;">​</a></h3><p>嘉靖二十四年（1545年），改建大享殿（即祈年殿），将原三色琉璃瓦屋顶改为统一青瓦。清乾隆年间，又将祈年殿、皇穹宇、圜丘坛等建筑全部改为蓝瓦金顶，形成今日面貌。</p><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><p>天坛分内坛和外坛，主要建筑集中在内坛。</p><h3 id="主要建筑" tabindex="-1">主要建筑 <a class="header-anchor" href="#主要建筑" aria-label="Permalink to &quot;主要建筑&quot;">​</a></h3><h4 id="祈年殿" tabindex="-1">祈年殿 <a class="header-anchor" href="#祈年殿" aria-label="Permalink to &quot;祈年殿&quot;">​</a></h4><p>祈年殿是天坛的主体建筑，是一座直径32米、高38米的圆形三重檐建筑。殿内28根楠木巨柱象征天空星辰：</p><ul><li>中央4根&quot;龙井柱&quot;象征四季</li><li>中圈12根&quot;金柱&quot;象征十二月</li><li>外圈12根&quot;檐柱&quot;象征十二时辰</li></ul><p>殿顶三层蓝色琉璃瓦代表天，鎏金宝顶熠熠生辉。</p><h4 id="圜丘坛" tabindex="-1">圜丘坛 <a class="header-anchor" href="#圜丘坛" aria-label="Permalink to &quot;圜丘坛&quot;">​</a></h4><p>圜丘坛是皇帝冬至祭天的场所，是一座三层汉白玉圆坛。坛面、台阶、栏杆所用石块均为九或九的倍数，象征&quot;九重天&quot;。站在坛心石上说话，声音会被放大，产生奇妙的回音效果。</p><h4 id="皇穹宇" tabindex="-1">皇穹宇 <a class="header-anchor" href="#皇穹宇" aria-label="Permalink to &quot;皇穹宇&quot;">​</a></h4><p>皇穹宇是供奉祭天神牌的场所，以其著名的&quot;回音壁&quot;而闻名。围墙是磨砖对缝的圆形围墙，声波可以沿墙面传播，两人分站东西两侧，贴墙说话，声音清晰可闻。</p><h4 id="丹陛桥" tabindex="-1">丹陛桥 <a class="header-anchor" href="#丹陛桥" aria-label="Permalink to &quot;丹陛桥&quot;">​</a></h4><p>连接圜丘坛和祈年殿的甬道，长360米、宽29.4米，比地面高出2.5米，称为&quot;海墁大道&quot;或&quot;丹陛桥&quot;，是天坛的&quot;神路&quot;。</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="祭天礼仪" tabindex="-1">祭天礼仪 <a class="header-anchor" href="#祭天礼仪" aria-label="Permalink to &quot;祭天礼仪&quot;">​</a></h3><p>天坛祭天是明清两代最重要的国家典礼之一。每年冬至，皇帝要在圜丘坛举行祭天大典。仪式极其隆重：皇帝提前三天到斋宫斋戒，祭天当天身着礼服，在乐舞伴奏下，向皇天上帝献祭。</p><h3 id="祈年殿的传说" tabindex="-1">祈年殿的传说 <a class="header-anchor" href="#祈年殿的传说" aria-label="Permalink to &quot;祈年殿的传说&quot;">​</a></h3><p>传说祈年殿是按照&quot;天圆地方&quot;的理念设计的。殿内中央的&quot;龙井柱&quot;取材于云南深山老林，运送进京耗费巨大人力物力。民间传说，这些柱子是&quot;神木&quot;，有避邪镇宅的功效。</p><h3 id="天心石" tabindex="-1">天心石 <a class="header-anchor" href="#天心石" aria-label="Permalink to &quot;天心石&quot;">​</a></h3><p>圜丘坛中心有一块圆形石板，称为&quot;天心石&quot;或&quot;亿兆景从石&quot;。据说站在上面呼唤，会得到上天回应，声音会被放大数倍。其实这是声波反射造成的声学现象。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约3小时）</strong>：</p><p>南门 → 圜丘坛 → 皇穹宇（回音壁） → 丹陛桥 → 祈年殿 → 皇乾殿 → 北门</p><p><strong>深度路线（约4-5小时）</strong>：</p><p>南门 → 昭亨门 → 圜丘坛 → 皇穹宇 → 回音壁 → 丹陛桥 → 祈年殿 → 皇乾殿 → 斋宫 → 神乐署 → 西门</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>门票选择</strong>：建议购买联票，否则看不到祈年殿等精华景点</li><li><strong>最佳时间</strong>：早上7:30前入园可以避开人流，还能看到晨练的老人</li><li><strong>拍照位置</strong>：祈年殿正面台阶处、圜丘坛中心都是绝佳拍照点</li><li><strong>回音壁</strong>：现在为了保护文物，回音壁已被围栏隔开，回音效果不如从前</li><li><strong>附近美食</strong>：南门涮肉（老北京铜锅涮肉）就在天坛南门对面，非常推荐</li></ol><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>1998年，天坛被联合国教科文组织列入《世界遗产名录》。世界遗产委员会评价：</p><blockquote><p>&quot;天坛是建筑和景观设计之杰作，其布局体现了中国传统的宇宙观和天人合一的思想，是中国古代祭祀建筑的杰出代表。&quot;</p></blockquote><p>天坛的设计融合了中国古代&quot;天圆地方&quot;&quot;天人合一&quot;的哲学思想，是中国古代建筑艺术的瑰宝。</p><hr><p><strong>📍 地址</strong>：北京市东城区天坛东里甲1号 <strong>📞 电话</strong>：010-67028866 <strong>🌐 官网</strong>：<a href="http://www.tiantanpark.com" target="_blank" rel="noreferrer">www.tiantanpark.com</a></p>',45)])])}const c=a(l,[["render",n]]);export{p as __pageData,c as default};
